#include<bits/stdc++.h>
using namespace std;
double pow(double x){
    return x*x;
}
double poer(double x1,double x2,double y1,double y2){
    return sqrt(pow(x2-x1)/1.0+pow(y2-y1));
}
int main(){
    double x1,x2,x3,y1,y2,y3;
    cin>>x1>>y1>>x2>>y2>>x3>>y3;
    printf("%.2lf",double(poer(x1,x2,y1,y2)+poer(x1,x3,y1,y3)+poer(x2,x3,y2,y3)));
}
